INSERT INTO questions
  (id, specialty, stem, choices, correct_answer, explanation, telemetry, domain_name, subtopic, difficulty, "references", status, category)
VALUES
('authored-batch-r20-013', 'Endocrine', 'A 47-year-old woman is scheduled for laparoscopic resection of a 5-cm right adrenal mass. She has a 6-month history of episodic pounding headaches, palpitations, and diaphoresis, and plasma free metanephrines are markedly elevated. In clinic her blood pressure is 178/104 mmHg and heart rate is 96 bpm. The surgical team asks the anesthesia care team to begin pharmacologic optimization before surgery. Which of the following is the most appropriate FIRST step in her preoperative preparation?', '[{"text":"Start oral metoprolol to control the heart rate, then add an alpha-blocker once the rate is at goal","label":"A","correct":false,"rationale":"Initiating beta-blockade before adequate alpha-blockade leaves alpha-mediated vasoconstriction unopposed and can precipitate a hypertensive crisis, so this sequence is incorrect."},{"text":"Start a continuous nicardipine infusion and proceed to surgery the same week without oral therapy","label":"B","correct":false,"rationale":"Calcium-channel blockers are useful adjuncts but do not replace several days of oral alpha-blockade and volume repletion, so proceeding immediately is inappropriate."},{"text":"Begin alpha-adrenergic blockade (e.g., phenoxybenzamine or doxazosin) and liberalize salt and fluid intake for 10-14 days","label":"C","correct":true,"rationale":"Alpha-blockade first controls catecholamine-driven vasoconstriction and, with volume expansion, re-fills the contracted intravascular space, making it the correct initial step."},{"text":"Administer intravenous magnesium sulfate as the sole preoperative agent for several days","label":"D","correct":false,"rationale":"Magnesium is a helpful intraoperative adjunct to blunt catecholamine surges but is not a stand-alone outpatient preparation regimen."},{"text":"Withhold all antihypertensives so intraoperative blood pressure lability can guide vasopressor titration","label":"E","correct":false,"rationale":"Leaving the patient unblocked invites catastrophic hypertensive surges on tumor manipulation, so withholding therapy is dangerous and wrong."}]'::jsonb, 'C', 'Catecholamine-secreting tumors require alpha-adrenergic blockade as the first step, started roughly 10-14 days preoperatively along with sodium and fluid loading to re-expand the chronically constricted intravascular volume. Beta-blockade is added only AFTER alpha-blockade is established; giving a beta-blocker first removes beta-2-mediated vasodilation and leaves alpha-mediated vasoconstriction unopposed, which can trigger a hypertensive crisis and acute heart failure. Adequacy of preparation is judged by normalized blood pressure, mild orthostatic hypotension, and resolution of symptoms.', '{}'::jsonb, 'Subspecialty Care', 'Pheochromocytoma resection - preoperative alpha- vs beta-blockade sequencing', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK589634/","source":"Perioperative Management of Pheochromocytoma - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Endocrine'),
('authored-batch-r20-014', 'Endocrine', 'A 58-year-old man with type 2 diabetes (HbA1c 7.2%) presents on postoperative day 1 after an uncomplicated elective right hemicolectomy. He is nauseated, tachypneic with a respiratory rate of 26, and reports malaise. Vitals: HR 104, BP 118/72, SpO2 98% on room air. Fingerstick glucose is 162 mg/dL. Arterial blood gas shows pH 7.21, HCO3 13 mEq/L, anion gap 22, and serum beta-hydroxybutyrate is elevated. His home medications include metformin and empagliflozin, the latter taken until the morning before surgery. Which factor most directly explains this presentation, and what should have been done differently?', '[{"text":"He developed hyperosmolar hyperglycemic state; the metformin should have been continued perioperatively","label":"A","correct":false,"rationale":"HHS produces glucose typically above 600 mg/dL without significant ketoacidosis, which does not match this near-normal glucose with a wide-gap metabolic acidosis and ketonemia."},{"text":"This is lactic acidosis from metformin; the empagliflozin was appropriately stopped and is unrelated","label":"B","correct":false,"rationale":"Metformin-associated lactic acidosis does not produce ketonemia and elevated beta-hydroxybutyrate, so this misattributes the gap to lactate."},{"text":"This is a normal postoperative stress response; no medication change was indicated","label":"C","correct":false,"rationale":"A pH of 7.21 with a wide anion gap and ketonemia is a pathologic ketoacidosis, not a benign stress response."},{"text":"The empagliflozin precipitated euglycemic diabetic ketoacidosis; it should have been held about 3-4 days before surgery","label":"D","correct":true,"rationale":"SGLT2 inhibitors cause ketoacidosis with near-normal glucose via glycosuria and shifted substrate metabolism, and guidelines call for holding them 3-4 days preoperatively, making this correct."},{"text":"He has acute kidney injury causing uremic acidosis; SGLT2 inhibitors prevent this and should be restarted","label":"E","correct":false,"rationale":"Uremic acidosis is driven by retained organic acids with elevated BUN/creatinine, not ketones, and does not fit the clinical picture."}]'::jsonb, 'D', 'SGLT2 inhibitors (empagliflozin, dapagliflozin, canagliflozin) can precipitate euglycemic diabetic ketoacidosis in the perioperative period: persistent glycosuria lowers plasma glucose while fasting, stress, and volume shifts drive lipolysis and ketogenesis, so the patient is acidotic and ketotic despite a near-normal glucose. Because glucose is not strikingly high, the diagnosis is easily missed; any perioperative patient on an SGLT2 inhibitor with unexplained anion-gap acidosis or tachypnea should have ketones checked. Current FDA and society guidance recommends holding these agents roughly 3-4 days before elective surgery, and these drugs can cause prolonged ketonemia even after they are stopped.', '{}'::jsonb, 'Subspecialty Care', 'SGLT2 inhibitors and perioperative euglycemic diabetic ketoacidosis', 'hard', '[{"url":"https://www.apsf.org/article/editorial-euglycemic-ketoacidosis-concerns-in-perioperative-use-of-sglt2-inhibitors-re-examining-current-recommendations/","source":"Editorial: Euglycemic Ketoacidosis Concerns in Perioperative Use of SGLT2 Inhibitors - Anesthesia Patient Safety Foundation"}]'::jsonb, 'sme_review', 'Endocrine'),
('authored-batch-r20-015', 'Endocrine', 'A 34-year-old woman with poorly controlled Graves disease undergoes emergency appendectomy. Two hours postoperatively she becomes agitated and confused, with temperature 40.1 C, HR 156 (atrial fibrillation), and BP 150/60 mmHg. Thyroid storm is diagnosed and the team begins propranolol, propylthiouracil, hydrocortisone, and active cooling. The resident then prepares to give potassium iodide (SSKI) immediately to block hormone release. Regarding the iodide, what is the most appropriate action?', '[{"text":"Give the iodide before the propylthiouracil to halt hormone release as quickly as possible","label":"A","correct":false,"rationale":"Giving iodide before the thionamide can supply substrate for new hormone synthesis and transiently worsen thyrotoxicosis, so this order is wrong."},{"text":"Omit the iodide entirely because it has no role in thyroid storm","label":"B","correct":false,"rationale":"Iodide is a standard component of storm therapy via the Wolff-Chaikoff effect to inhibit hormone release, so omitting it is incorrect."},{"text":"Replace the propylthiouracil with iodide, since both block hormone synthesis by the same mechanism","label":"C","correct":false,"rationale":"Iodide chiefly blocks hormone RELEASE while thionamides block SYNTHESIS, so they are complementary rather than interchangeable."},{"text":"Give iodide only if the propranolol fails to control the heart rate","label":"D","correct":false,"rationale":"Iodide addresses hormone release, not rate control, and its use is not contingent on the response to beta-blockade."},{"text":"Give the iodide at least about 1 hour AFTER the propylthiouracil has been administered","label":"E","correct":true,"rationale":"Administering the thionamide first blocks new hormone synthesis so that the iodide''s substrate load is not converted into additional stored hormone, making delayed iodide the correct approach."}]'::jsonb, 'E', 'In thyroid storm, the thionamide (propylthiouracil or methimazole) is given FIRST to block new thyroid hormone synthesis; iodide is then added about an hour later to inhibit hormone release (Wolff-Chaikoff effect). If iodide is given before the synthesis pathway is blocked, the extra iodine can be organified into newly synthesized hormone and transiently worsen the thyrotoxic state. PTU is often preferred acutely because it also blocks peripheral T4-to-T3 conversion; beta-blockade (propranolol) controls adrenergic symptoms and rate, and glucocorticoids treat relative adrenal insufficiency while also reducing peripheral conversion.', '{}'::jsonb, 'Subspecialty Care', 'Thyroid storm - sequencing of thionamide before iodide', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK448095/","source":"Thyroid Storm - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Endocrine'),
('authored-batch-r20-016', 'Ophthalmic', 'A 64-year-old man with type 2 diabetes (last HbA1c 7.1%) and well-controlled hypertension underwent pars plana vitrectomy 9 days ago for a tractional retinal detachment, during which the surgeon injected a 14% perfluoropropane (C3F8) gas tamponade. He now presents for an urgent open reduction of a fractured ankle and requires general anesthesia. Vitreoretinal records confirm a residual intraocular gas bubble is still present on slit-lamp exam. Which of the following intraoperative anesthetic decisions is MOST critical to preventing a vision-threatening complication?', '[{"text":"Avoid nitrous oxide and maintain anesthesia with an air/oxygen and volatile or total intravenous technique","label":"A","correct":true,"rationale":"Correct: nitrous oxide is far more soluble than the intraocular fluorinated gas, so it diffuses into the bubble faster than the gas leaves, expanding it and raising intraocular pressure enough to compromise central retinal artery perfusion."},{"text":"Avoid succinylcholine because it will rupture the closed globe through extraocular muscle contraction","label":"B","correct":false,"rationale":"Incorrect: the globe is intact and closed after vitrectomy, and the transient intraocular pressure rise from succinylcholine does not threaten a sealed eye the way an unabsorbed expandable gas bubble does."},{"text":"Maintain an end-tidal CO2 of 30 mmHg to reduce choroidal blood volume and shrink the bubble","label":"C","correct":false,"rationale":"Incorrect: modest hypocapnia does not meaningfully alter a fixed-volume intraocular gas bubble and ignores the dominant mechanism of nitrous-oxide-driven expansion."},{"text":"Administer intravenous acetazolamide prophylactically to keep the bubble from enlarging","label":"D","correct":false,"rationale":"Incorrect: acetazolamide lowers aqueous production but cannot offset rapid nitrous oxide influx into the bubble, so it is no substitute for simply withholding nitrous oxide."},{"text":"Position the patient strictly supine to keep the gas bubble away from the optic nerve head","label":"E","correct":false,"rationale":"Incorrect: positioning influences which retinal break the bubble tamponades but does nothing to prevent the gas-volume expansion and pressure spike caused by nitrous oxide."}]'::jsonb, 'A', 'An intraocular gas bubble (SF6 or C3F8) creates a closed, expandable air-filled space. Because nitrous oxide is roughly 20-30 times more soluble in blood than these fluorinated gases, it enters the bubble faster than the gas can leave, increasing bubble volume and intraocular pressure to the point of central retinal artery occlusion and blindness. Nitrous oxide must be avoided while any bubble persists, which is up to several weeks for SF6 and longer for C3F8, so confirmation of a residual bubble mandates a nitrous-free technique.', '{}'::jsonb, 'Subspecialty Care', 'Intraocular gas tamponade and nitrous oxide expansion', 'medium', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK572131/","source":"Anesthesia for Ophthalmic Surgery (StatPearls)"}]'::jsonb, 'sme_review', 'Ophthalmic'),
('authored-batch-r20-017', 'Ophthalmic', 'A 27-year-old man is brought emergently for repair of an open-globe injury after being struck in the eye by a metal fragment; vitreous is visibly extruding. He ate a full meal 90 minutes ago and is in pain and retching. He has no other comorbidities (ASA II). The anesthesiologist must perform a rapid-sequence induction to secure the airway while minimizing the risk of expelling intraocular contents. Which approach BEST balances aspiration risk against the goal of avoiding a rise in intraocular pressure?', '[{"text":"Inhalational induction with sevoflurane and spontaneous ventilation, deferring any neuromuscular blocker","label":"A","correct":false,"rationale":"Incorrect: a slow inhalational induction in a full-stomach patient who is actively retching maximizes aspiration risk and does not reliably blunt the intraocular pressure rise from coughing or laryngoscopy."},{"text":"A modified rapid-sequence induction using high-dose rocuronium with adequate intravenous induction agent and opioid to blunt the laryngoscopy response","label":"B","correct":true,"rationale":"Correct: a non-depolarizing relaxant such as high-dose rocuronium provides rapid intubating conditions without the intraocular pressure rise associated with succinylcholine, while a deep induction with opioid blunts the pressor and IOP response to laryngoscopy in this full-stomach patient."},{"text":"Awake fiberoptic intubation with topical airway anesthesia and minimal sedation","label":"C","correct":false,"rationale":"Incorrect: an awake, coughing, straining patient generates large intraocular pressure spikes (and the Valsalva of gagging) that directly threaten extrusion of globe contents."},{"text":"Rapid-sequence induction with succinylcholine because controlling the airway quickly outweighs any theoretical intraocular pressure concern","label":"D","correct":false,"rationale":"Incorrect: succinylcholine transiently raises intraocular pressure through tonic extraocular muscle contraction, which is the one preventable IOP rise to avoid in an open globe when an equally fast non-depolarizer is available."},{"text":"Induce with ketamine alone to preserve airway reflexes and spontaneous breathing without a relaxant","label":"E","correct":false,"rationale":"Incorrect: relying on preserved airway reflexes means the patient may cough and strain, and ketamine without neuromuscular blockade provides poor intubating conditions in a struggling full-stomach trauma patient."}]'::jsonb, 'B', 'In open-globe injury the anesthetic must reconcile two competing imperatives: protecting against aspiration in a usually full-stomach trauma patient and preventing any rise in intraocular pressure that could extrude vitreous or other contents. A modified rapid-sequence induction with a deep induction dose, an opioid to blunt the laryngoscopy pressor response, and a high-dose non-depolarizing relaxant (rocuronium) delivers fast intubating conditions without the IOP rise classically attributed to succinylcholine. Avoiding coughing, straining, and external pressure on the globe is the unifying principle.', '{}'::jsonb, 'Subspecialty Care', 'Open-globe injury: airway management and intraocular pressure', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK551637/","source":"Globe Rupture (StatPearls)"}]'::jsonb, 'sme_review', 'Ophthalmic'),
('authored-batch-r20-018', 'Ophthalmic', 'A 72-year-old woman with mild, well-controlled hypertension is scheduled for elective cataract extraction under monitored anesthesia care. The ophthalmologist places a retrobulbar block after light sedation. Shortly after the block injection, the patient becomes confused, then apneic with a fixed dilated contralateral pupil, and her blood pressure and heart rate fall. Which complication of the block is the MOST likely explanation for this constellation of findings?', '[{"text":"Retrobulbar hemorrhage causing acute orbital compartment syndrome","label":"A","correct":false,"rationale":"Incorrect: retrobulbar hemorrhage produces a tense, proptotic eye with rising intraocular pressure rather than sudden apnea, altered consciousness, and contralateral pupillary signs."},{"text":"Oculocardiac reflex triggered by needle-induced traction on the extraocular muscles","label":"B","correct":false,"rationale":"Incorrect: the oculocardiac reflex causes bradycardia and occasionally asystole but does not by itself cause apnea, confusion, or a fixed contralateral pupil."},{"text":"Brainstem anesthesia from inadvertent injection of local anesthetic into the optic nerve sheath with spread to the subarachnoid space","label":"C","correct":true,"rationale":"Correct: local anesthetic tracking along the optic nerve dural sheath into the CSF spreads to the brainstem, producing apnea, altered mental status, cardiovascular instability, and contralateral cranial nerve signs within minutes of the block."},{"text":"Globe perforation by the block needle","label":"D","correct":false,"rationale":"Incorrect: globe perforation causes pain, sudden loss of vision, and vitreous hemorrhage localized to the eye, not the central nervous system signs of apnea and altered consciousness."},{"text":"Systemic local anesthetic toxicity from intravascular absorption of the block dose","label":"E","correct":false,"rationale":"Incorrect: while local anesthetic systemic toxicity can cause CNS and cardiac effects, the small ophthalmic block volume and the hallmark contralateral pupillary involvement point specifically to subarachnoid brainstem spread rather than systemic absorption."}]'::jsonb, 'C', 'Brainstem anesthesia is a recognized complication of retrobulbar and deep peribulbar blocks: the needle penetrates the optic nerve dural sheath and deposits local anesthetic that tracks into the subarachnoid space and reaches the brainstem. The classic picture is the onset, within minutes, of confusion progressing to apnea, hemodynamic instability, and crossed cranial nerve findings such as a contralateral dilated pupil. Management is supportive — secure the airway, ventilate, and support the circulation until the local anesthetic redistributes, with full recovery expected once it does.', '{}'::jsonb, 'Subspecialty Care', 'Regional ophthalmic block complications: brainstem anesthesia', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/regional-anesthesia-for-ophthalmic-surgery/","source":"Regional Anesthesia for Ophthalmic Surgery (OpenAnesthesia)"}]'::jsonb, 'sme_review', 'Ophthalmic');
